package com.chaobo.scm.supplier.application.finance;
import com.chaobo.scm.common.api.PageResult;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.shared.*;import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import com.chaobo.scm.supplier.infrastructure.persistence.finance.SupplierFinanceMapper;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.math.*;
@Service public class SupplierFinanceApplicationService{private final SupplierFinanceMapper mapper;private final IdentifierGenerator ids;private final AuditLogRepository audit;public SupplierFinanceApplicationService(SupplierFinanceMapper mapper,IdentifierGenerator ids,AuditLogRepository audit){this.mapper=mapper;this.ids=ids;this.audit=audit;}@Transactional(readOnly=true)public PageResult<FinanceViews.Reconciliation> reconciliations(Long supplierId,Long scope,Integer status,int page,int size){checkPage(page,size);Long s=scope==null?supplierId:scope;return new PageResult<>(page,size,mapper.reconciliationCount(s,status),mapper.reconciliations(s,status,(page-1)*size,size));}@Transactional(readOnly=true)public PageResult<FinanceViews.Invoice> invoices(Long supplierId,Long scope,Integer status,int page,int size){checkPage(page,size);Long s=scope==null?supplierId:scope;return new PageResult<>(page,size,mapper.invoiceCount(s,status),mapper.invoices(s,status,(page-1)*size,size));}@Transactional public void importStatement(String no,long supplierId,String currency,BigDecimal amount,int sourceVersion){if(no==null||no.isBlank()||supplierId<=0||currency==null||currency.length()!=3||amount==null||amount.signum()<0)throw rule("对账单数据不合法");mapper.upsertStatement(ids.nextId(),no,supplierId,currency,amount,sourceVersion);}@Transactional public void confirm(long id,int version,BigDecimal amount,String differenceReason,CommandContext c){c.requirePermission("supplier:reconciliation:confirm");var row=getReconciliation(id);c.requireSupplierScope(row.supplierId());if(amount==null||amount.signum()<0)throw rule("确认金额不合法");boolean same=amount.compareTo(row.statementAmount())==0;if(!same&&(differenceReason==null||differenceReason.isBlank()))throw rule("对账金额不一致必须填写差异原因");if(mapper.respond(id,version,amount,same?2:3,same?null:differenceReason)!=1)throw conflict();audit.save(c,same?"CONFIRM_RECONCILIATION":"REPORT_RECONCILIATION_DIFFERENCE","RECONCILIATION",id,row.statementNo(),null,"{\"status\":"+(same?2:3)+"}");}@Transactional public void withdraw(long id,int version,CommandContext c){c.requirePermission("supplier:reconciliation:withdraw");var row=getReconciliation(id);c.requireSupplierScope(row.supplierId());if(mapper.changeStatus(id,version,4)!=1)throw conflict();audit.save(c,"WITHDRAW_RECONCILIATION","RECONCILIATION",id,row.statementNo(),null,"{\"status\":4}");}@Transactional public long uploadInvoice(String no,long supplierId,Long reconciliationId,int type,BigDecimal net,BigDecimal tax,BigDecimal rate,String url,CommandContext c){c.requirePermission("supplier:invoice:upload");c.requireSupplierScope(supplierId);if(no==null||no.isBlank()||type<1||type>3||net==null||net.signum()<0||tax==null||tax.signum()<0||rate==null||rate.signum()<0||url==null||url.isBlank())throw rule("发票数据不合法");if(net.multiply(rate).setScale(2,RoundingMode.HALF_UP).compareTo(tax.setScale(2,RoundingMode.HALF_UP))!=0)throw rule("税额与不含税金额、税率不匹配");long id=ids.nextId();mapper.insertInvoice(id,no,supplierId,reconciliationId,type,net,tax,rate,url);audit.save(c,"UPLOAD_INVOICE","INVOICE",id,no,null,"{\"status\":1}");return id;}@Transactional public void recordInvoiceValidation(long id,boolean passed,String message){var row=mapper.invoice(id);if(row==null)throw new BusinessException(ErrorCode.NOT_FOUND,"发票不存在");if(!passed&&(message==null||message.isBlank()))throw rule("校验失败必须说明原因");if(mapper.validateInvoice(id,passed?2:3,message)!=1)throw conflict();}private FinanceViews.Reconciliation getReconciliation(long id){var r=mapper.reconciliation(id);if(r==null)throw new BusinessException(ErrorCode.NOT_FOUND,"对账单不存在");return r;}private static void checkPage(int p,int s){if(p<1||s<1||s>100)throw rule("分页参数不合法");}private static BusinessException rule(String m){return new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,m);}private static BusinessException conflict(){return new BusinessException(ErrorCode.VERSION_CONFLICT,"数据状态或版本已变更");}}
